sys_script_include.script:
var AnomalySummaryGenerator = Class.create();

AnomalySummaryGenerator.prototype = {

    initialize: function() {
        this.log = new GSLog('u_anomaly.log.level', 'AnomalySummaryGenerator');
    },

    /**
     * Generate and attach AI summary for an anomaly event.
     * @param {String} anomalyEventSysId - sys_id of u_anomaly_event
     * @param {String} incidentSysId     - sys_id of linked incident
     */
    generateAndAttach: function(anomalyEventSysId, incidentSysId) {

        var anomalyGr = new GlideRecord('u_anomaly_event');
        if (!anomalyGr.get(anomalyEventSysId)) {
            this.log.logError('generateAndAttach | Anomaly event not found: ' + anomalyEventSysId);
            return;
        }

        var context = this._buildContext(anomalyGr);
        var prompt  = this._buildPrompt(context);
        var summary = this._invokeNowAssist(prompt);

        if (summary) {
            this._attachToIncident(incidentSysId, summary, anomalyGr.number.toString());
            this.log.logInfo('generateAndAttach | Summary attached to incident ' + incidentSysId);
        }
    },

    _buildContext: function(anomalyGr) {
        return {
            ci:           anomalyGr.u_configuration_item.getDisplayValue(),
            state:        anomalyGr.u_state.getDisplayValue(),
            signalCount:  anomalyGr.u_signal_count.toString(),
            detectedOn:   anomalyGr.u_detected_on.getDisplayValue(),
            signalName:   anomalyGr.u_signal_name.toString()
        };
    },

    _buildPrompt: function(ctx) {
        return 'You are an ITSM operations expert. Analyze the following anomaly detection event and provide:\n' +
               '1. A plain English summary of what is happening\n' +
               '2. Likely root cause hypothesis based on the signal\n' +
               '3. Immediate recommended actions for the on-call team\n\n' +
               'Context:\n' +
               '- Configuration Item: ' + ctx.ci + '\n' +
               '- Current Service State: ' + ctx.state + '\n' +
               '- KPI Signal Name: ' + ctx.signalName + '\n' +
               '- Number of Active Signals: ' + ctx.signalCount + '\n' +
               '- Anomaly First Detected: ' + ctx.detectedOn + '\n\n' +
               'Keep the summary concise (under 300 words). Use bullet points for recommendations.';
    },

    _invokeNowAssist: function(prompt) {
        try {
            // Now Assist GenAI invocation via sn_now_assist API
            // Replace with actual Now Assist Skill sys_id for your instance
            var request  = new sn_now_assist.NowAssistRequest();
            request.setInput(prompt);
            request.setSkill('u_anomaly_summary_skill'); // Custom NASK sys_name

            var response = request.execute();
            if (response && response.getOutput()) {
                return response.getOutput();
            }
        } catch(e) {
            this.log.logError('_invokeNowAssist | Now Assist invocation failed: ' + e.message +
                '\nFalling back to template summary.');
            return this._fallbackSummary(prompt);
        }
        return null;
    },

    _fallbackSummary: function(prompt) {
        return 'AI summary unavailable — Now Assist service unreachable.\n' +
               'Please review the anomaly event manually and assess impact.';
    },

    _attachToIncident: function(incidentSysId, summary, anomalyNumber) {
        var gr = new GlideRecord('incident');
        if (!gr.get(incidentSysId)) return;

        var existing = gr.work_notes.toString();
        gr.work_notes = '=== AI Anomaly Summary (Generated by AnomalySummaryGenerator) ===\n' +
                        'Anomaly Event: ' + anomalyNumber + '\n\n' +
                        summary + '\n\n' +
                        '======================================================\n' +
                        existing;
        gr.update();
    },

    type: 'AnomalySummaryGenerator'
};
